const crypto = require('crypto');
const fs = require('fs');
const https = require('https');

const SA = JSON.parse(fs.readFileSync('inbox/sheetsms-470810-d89dad35a23c.json','utf8'));
const SPREADSHEET = '194HkFrBbUaQd3Zd6avIfjUWPfuwsUDCWyFuj71J9LYg';
const b64url = b => Buffer.from(b).toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');

function reqJSON(opts, body){
  return new Promise((res,rej)=>{
    const r=https.request(opts,resp=>{let d='';resp.on('data',c=>d+=c);resp.on('end',()=>res({status:resp.statusCode,body:d}));});
    r.on('error',rej); if(body)r.write(body); r.end();
  });
}

(async()=>{
  // 1) Build & sign JWT
  const now=Math.floor(Date.now()/1000);
  const header=b64url(JSON.stringify({alg:'RS256',typ:'JWT'}));
  const claim=b64url(JSON.stringify({
    iss:SA.client_email, scope:'https://www.googleapis.com/auth/spreadsheets',
    aud:SA.token_uri, iat:now, exp:now+3600
  }));
  const signingInput=header+'.'+claim;
  const sig=crypto.sign('RSA-SHA256',Buffer.from(signingInput),SA.private_key)
    .toString('base64').replace(/\+/g,'-').replace(/\//g,'_').replace(/=+$/,'');
  const jwt=signingInput+'.'+sig;

  // 2) Exchange for access_token
  const form='grant_type='+encodeURIComponent('urn:ietf:params:oauth:grant-type:jwt-bearer')+'&assertion='+jwt;
  const tok=await reqJSON({hostname:'oauth2.googleapis.com',path:'/token',method:'POST',
    headers:{'Content-Type':'application/x-www-form-urlencoded','Content-Length':Buffer.byteLength(form)}},form);
  console.log('[token exchange] HTTP',tok.status);
  if(tok.status!==200){console.log(tok.body);process.exit(1);}
  const at=JSON.parse(tok.body).access_token;
  console.log('[token] access_token obtained, length',at.length,'expires_in',JSON.parse(tok.body).expires_in);
  const AUTH={Authorization:'Bearer '+at};

  // 3) ACCEPTANCE A: GET title (read via Sheets API)
  const title=await reqJSON({hostname:'sheets.googleapis.com',
    path:`/v4/spreadsheets/${SPREADSHEET}?fields=properties.title`,method:'GET',headers:AUTH});
  console.log('[GET title] HTTP',title.status,'->',title.body);

  // 4) ACCEPTANCE B: prove WRITE non-destructively via temp sheet
  const add=await reqJSON({hostname:'sheets.googleapis.com',
    path:`/v4/spreadsheets/${SPREADSHEET}:batchUpdate`,method:'POST',
    headers:{...AUTH,'Content-Type':'application/json'}},
    JSON.stringify({requests:[{addSheet:{properties:{title:'_conn_test_tmp'}}}]}));
  console.log('[addSheet temp tab] HTTP',add.status);
  let tmpId=null;
  if(add.status===200){tmpId=JSON.parse(add.body).replies[0].addSheet.properties.sheetId;}
  else {console.log(add.body);}

  if(tmpId!==null){
    const upd=await reqJSON({hostname:'sheets.googleapis.com',
      path:`/v4/spreadsheets/${SPREADSHEET}/values/_conn_test_tmp!A1?valueInputOption=RAW`,method:'PUT',
      headers:{...AUTH,'Content-Type':'application/json'}},
      JSON.stringify({values:[['connector OAuth write OK '+new Date().toISOString()]]}));
    console.log('[values.update test cell] HTTP',upd.status,'->',upd.body);

    const del=await reqJSON({hostname:'sheets.googleapis.com',
      path:`/v4/spreadsheets/${SPREADSHEET}:batchUpdate`,method:'POST',
      headers:{...AUTH,'Content-Type':'application/json'}},
      JSON.stringify({requests:[{deleteSheet:{sheetId:tmpId}}]}));
    console.log('[deleteSheet cleanup] HTTP',del.status,'(temp tab removed, boary data untouched)');
  }
  console.log('=== DONE ===');
})().catch(e=>{console.error('ERR',e);process.exit(1);});
EOF
